// DoD C-1: survey_responses 테이블 스키마
export interface SurveyResponse {
  id: string
  hashed_id: string          // DoD D-1: 직접 식별자 없이 해시만
  session_token: string      // Magic Link 세션 연결용
  consent_given: boolean     // DoD D-2: 동의 여부
  consented_at: string | null
  submitted_at: string       // DoD C-2: 타임스탬프
  responses: QuestionResponse[]
  created_at: string
}

export interface QuestionResponse {
  question_id: string
  question_text: string
  answer: string
}

// DoD B-1: 주관식 문항 타입
export interface SurveyQuestion {
  id: string
  text: string
  type: 'text' | 'textarea'
  required: boolean
  placeholder?: string
}

// 폼 상태 타입
export interface SurveyFormState {
  step: 'consent' | 'survey' | 'complete' | 'error'
  consent: boolean
  answers: Record<string, string>
  errors: Record<string, string>
  isSubmitting: boolean
  submitError: string | null
}

// Magic Link 인증 상태
export interface AuthState {
  email: string
  sent: boolean
  error: string | null
  loading: boolean
}

// Supabase DB 타입
export type Database = {
  public: {
    Tables: {
      survey_responses: {
        Row: SurveyResponse
        Insert: Omit<SurveyResponse, 'id' | 'created_at'>
        Update: Partial<SurveyResponse>
      }
      consent_log: {
        Row: {
          id: string
          hashed_id: string
          consent_given: boolean
          consented_at: string
          ip_hash: string | null
        }
        Insert: Omit<ConsentLog, 'id'>
        Update: Partial<ConsentLog>
      }
    }
  }
}

interface ConsentLog {
  id: string
  hashed_id: string
  consent_given: boolean
  consented_at: string
  ip_hash: string | null
}

