'use server'

import { createServerSupabaseClient } from '@/lib/supabase/server'
import { hashEmail } from '@/lib/crypto'
import type { QuestionResponse } from '@/types'
import { z } from 'zod'

// ============================================================
// DoD A-1: Magic Link 발송
// ============================================================
const emailSchema = z.string().email('유효한 이메일 주소를 입력해 주세요')

export async function sendMagicLink(email: string) {
  const parsed = emailSchema.safeParse(email)
  if (!parsed.success) {
    return { success: false, error: parsed.error.errors[0].message }
  }

  const supabase = createServerSupabaseClient()

  const { error } = await supabase.auth.signInWithOtp({
    email: parsed.data,
    options: {
      emailRedirectTo: `${process.env.NEXTAUTH_URL}/auth/callback`,
      shouldCreateUser: true,
    },
  })

  if (error) {
    return { success: false, error: '링크 발송에 실패했습니다. 잠시 후 다시 시도해 주세요.' }
  }

  return { success: true }
}

// ============================================================
// DoD C-1, C-2, D-1, D-2, D-3: 설문 제출
// ============================================================
const submitSchema = z.object({
  answers: z.record(z.string()),
  consentGiven: z.literal(true, {
    errorMap: () => ({ message: '개인정보 수집에 동의하셔야 제출이 가능합니다' }),
  }), // DoD D-3: false면 서버에서도 차단
})

export async function submitSurvey(
  answers: Record<string, string>,
  consentGiven: boolean
) {
  // DoD D-3: 동의 없으면 서버에서 즉시 차단
  const parsed = submitSchema.safeParse({ answers, consentGiven })
  if (!parsed.success) {
    return {
      success: false,
      error: '동의 없이는 제출할 수 없습니다. (DoD D-3)',
    }
  }

  const supabase = createServerSupabaseClient()

  // 현재 세션에서 이메일 가져오기
  const { data: { session } } = await supabase.auth.getSession()
  if (!session?.user?.email) {
    return { success: false, error: '인증 세션이 만료되었습니다. 다시 로그인해 주세요.' }
  }

  // DoD D-1: 이메일 해싱 — 원문 저장 안 함
  const hashedId = await hashEmail(session.user.email)
  const sessionToken = session.access_token.slice(0, 32)

  // 응답 배열 변환
  const responses: QuestionResponse[] = Object.entries(answers).map(
    ([question_id, answer]) => ({
      question_id,
      question_text: '', // 나중에 질문 텍스트 포함 가능
      answer,
    })
  )

  // DoD C-1: survey_responses에 INSERT
  // DoD C-2: submitted_at은 DB 기본값 NOW()
  // DoD D-1: hashed_id만 저장, 이메일 원문 없음
  // DoD D-2: consent_given = true, consented_at 기록
  const { error: insertError } = await supabase
    .from('survey_responses')
    .insert({
      hashed_id: hashedId,
      session_token: sessionToken,
      consent_given: true,             // DoD D-2
      consented_at: new Date().toISOString(),
      responses,
      submitted_at: new Date().toISOString(), // DoD C-2
    })

  if (insertError) {
    console.error('[submitSurvey] DB insert error:', insertError)
    return {
      success: false,
      error: '저장 중 오류가 발생했습니다. 잠시 후 다시 시도해 주세요.',
    }
  }

  // 동의 감사 로그 기록 (DoD D-2)
  await supabase.from('consent_log').insert({
    hashed_id: hashedId,
    consent_given: true,
    consented_at: new Date().toISOString(),
    ip_hash: null, // 서버에서 IP 해싱 추가 가능
  })

  return { success: true }
}

