### 5-D. src/components/survey/SurveyStep.tsx

```typescript
'use client'

import { useState } from 'react'
import { SURVEY_QUESTIONS } from '@/lib/questions'

interface Props {
  onSubmit: (answers: Record<string, string>) => Promise<void>
  isSubmitting: boolean
  submitError: string | null
}

export default function SurveyStep({ onSubmit, isSubmitting, submitError }: Props) {
  const [answers, setAnswers] = useState<Record<string, string>>({})
  const [errors, setErrors] = useState<Record<string, string>>({})

  function validate(): boolean {
    const newErrors: Record<string, string> = {}
    SURVEY_QUESTIONS.forEach(q => {
      // DoD B-2: 필수 문항 빈칸 제출 차단
      if (q.required && !answers[q.id]?.trim()) {
        newErrors[q.id] = '필수 문항입니다. 내용을 입력해 주세요.'
      }
    })
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  async function handleSubmit(e: React.FormEvent) {
    e.preventDefault()
    if (!validate()) return
    await onSubmit(answers)
  }

  return (
    <form onSubmit={handleSubmit} className="max-w-lg mx-auto bg-white rounded-2xl shadow-sm p-8 space-y-6">
      <div className="w-10 h-1 bg-brand-red mb-2" />
      <h2 className="text-xl font-bold text-gray-900">이번 주 솔직한 이야기를 들려주세요</h2>
      <p className="text-sm text-gray-500">모든 응답은 익명으로 처리됩니다.</p>

      {/* DoD B-1: 주관식 문항 렌더링 */}
      {SURVEY_QUESTIONS.map((q, i) => (
        <div key={q.id}>
          <label className="block text-sm font-medium text-gray-800 mb-1">
            {i + 1}. {q.text}
            {q.required && <span className="text-brand-red ml-1">*</span>}
          </label>
          {q.type === 'textarea' ? (
            <textarea
              rows={4}
              placeholder={q.placeholder}
              value={answers[q.id] ?? ''}
              onChange={e => setAnswers(a => ({ ...a, [q.id]: e.target.value }))}
              className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm resize-none
                         focus:outline-none focus:ring-2 focus:ring-brand-red/30 focus:border-brand-red transition"
            />
          ) : (
            <input
              type="text"
              placeholder={q.placeholder}
              value={answers[q.id] ?? ''}
              onChange={e => setAnswers(a => ({ ...a, [q.id]: e.target.value }))}
              className="w-full border border-gray-200 rounded-lg px-4 py-3 text-sm
                         focus:outline-none focus:ring-2 focus:ring-brand-red/30 focus:border-brand-red transition"
            />
          )}
          {/* DoD B-2: 유효성 오류 메시지 */}
          {errors[q.id] && (
            <p className="text-xs text-red-500 mt-1">{errors[q.id]}</p>
          )}
        </div>
      ))}

      {/* DoD C-3: 네트워크 오류 메시지 */}
      {submitError && (
        <div className="bg-red-50 border border-red-100 rounded-lg px-4 py-3 text-sm text-red-600">
          {submitError}
          <br />
