### 6-B. src/app/actions.ts 전문

```typescript
'use server'

import { createServerSupabaseClient } from '@/lib/supabase/server'
import { hashEmail } from '@/lib/crypto'
import { z } from 'zod'

const emailSchema = z.string().email('유효한 이메일 주소를 입력해 주세요')

// DoD A-1
export async function sendMagicLink(email: string) {
  const parsed = emailSchema.safeParse(email)
  if (!parsed.success) return { success: false, error: parsed.error.errors[0].message }

  const supabase = createServerSupabaseClient()
  const { error } = await supabase.auth.signInWithOtp({
    email: parsed.data,
    options: { emailRedirectTo: `${process.env.NEXTAUTH_URL}/auth/callback` },
  })

  if (error) return { success: false, error: '링크 발송에 실패했습니다. 잠시 후 다시 시도해 주세요.' }
  return { success: true }
}

// DoD C-1, C-2, D-1, D-2, D-3
export async function submitSurvey(answers: Record<string, string>, consentGiven: boolean) {
  // DoD D-3: 동의 없으면 서버에서 즉시 차단
  if (!consentGiven) return { success: false, error: '동의 없이는 제출할 수 없습니다.' }

  const supabase = createServerSupabaseClient()
  const { data: { session } } = await supabase.auth.getSession()

  if (!session?.user?.email) {
    return { success: false, error: '인증 세션이 만료되었습니다. 다시 로그인해 주세요.' }
  }

  // DoD D-1: 이메일 해싱
  const hashedId = await hashEmail(session.user.email)
  const responses = Object.entries(answers).map(([question_id, answer]) => ({
    question_id,
    answer,
  }))

  // DoD C-1: INSERT / C-2: submitted_at / D-2: consent_given
  const { error } = await supabase.from('survey_responses').insert({
    hashed_id: hashedId,
    session_token: session.access_token.slice(0, 32),
    consent_given: true,
    consented_at: new Date().toISOString(),
    responses,
    submitted_at: new Date().toISOString(),
  })

  if (error) return { success: false, error: '저장 중 오류가 발생했습니다. 잠시 후 다시 시도해 주세요.' }

  await supabase.from('consent_log').insert({
    hashed_id: hashedId,
    consent_given: true,
    consented_at: new Date().toISOString(),
    ip_hash: null,
  })

  return { success: true }
}
```

