### 6-E. src/app/survey/SurveyClient.tsx

```typescript
'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import ConsentStep from '@/components/survey/ConsentStep'
import SurveyStep from '@/components/survey/SurveyStep'
import { submitSurvey } from '../actions'

export default function SurveyClient() {
  const router = useRouter()
  const [step, setStep] = useState<'consent' | 'survey'>('consent')
  const [isSubmitting, setIsSubmitting] = useState(false)
  const [submitError, setSubmitError] = useState<string | null>(null)

  async function handleSubmit(answers: Record<string, string>) {
    setIsSubmitting(true)
    setSubmitError(null)

    const result = await submitSurvey(answers, true) // DoD D-3

    if (result.success) {
      router.push('/survey/complete') // DoD B-3
    } else {
      setSubmitError(result.error ?? '오류가 발생했습니다.') // DoD C-3
    }
    setIsSubmitting(false)
  }

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center py-12 px-4">
      {step === 'consent' ? (
        <ConsentStep onConsent={() => setStep('survey')} />
      ) : (
        <SurveyStep
          onSubmit={handleSubmit}
          isSubmitting={isSubmitting}
          submitError={submitError}
        />
      )}
    </div>
  )
}
```

